(function(F) {
	'use strict';

	F.controller.make('Rows', {
		/**
		 * Under min message
		 */
		underMinMsg: null,

		/**
		 * Over max message
		 */
		overMaxMsg: null,

		/**
		 * Initialize controller
		 */
		init: function() {
			// Save a reference to the controller
			var self = this;

			// Watch for changes to numRows property
			self.sharedModelOther.onChange('numRows', function() {
				self.numRowsReact();
			});

			// Check length
			self.checkNumRows();

			// Watch for changes to the field change event
			self.sharedModel.onChange('fieldChangeEvent', function() {
				self.checkNumRows();
			});
		},

		/**
		 * Check length
		 */
		checkNumRows: function() {
			// Save a reference to the controller
			var self = this;

			// Get rows
			var $rows = self.sharedStorage.$tableBody.find('.js-ansel-row');

			// Set length on model
			self.sharedModelOther.set('numRows', $rows.length);
		},

		/**
		 * Num rows change
		 */
		numRowsReact: function() {
			// Save a reference to the controller
			var self = this;

			// Get the num rows
			var numRows = self.sharedModelOther.get('numRows');

			// Get field min qty
			var minQty = self.sharedModel.get('minQty');

			// Get field max qty
			var maxQty = self.sharedModel.get('maxQty');

			// Set a message variable
			var msg;

			// Set a tempQty variable
			var tempQty;

			// Destroy previous messages
			if (self.underMinMsg) {
				self.underMinMsg.destroy(false);
			}

			if (self.overMaxMsg) {
				self.overMaxMsg.destroy(false);
			}

			// Check if there's a min qty and if we're under it
			if (minQty && (numRows < minQty)) {
				tempQty = minQty;

				if (! numRows && minQty === 1) {
					msg = self.sharedStorage.getLang('mustAdd1Image');
				} else if (! numRows) {
					msg = self.sharedStorage.getLang('mustAddQtyImages');
				} else {
					tempQty = minQty - numRows;

					if (tempQty === 1) {
						msg = self.sharedStorage.getLang('mustAdd1MoreImage');
					} else {
						msg = self.sharedStorage.getLang('mustAddQtyMoreImages');
					}
				}

				// Show a message
				self.underMinMsg = F.controller.construct('Message', {
					autoRender: true,
					msg: msg.replace('{{qty}}', tempQty),
					sharedModel: self.sharedModel,
					sharedStorage: self.sharedStorage
				});
			}

			if (self.sharedModel.get('preventUploadOverMax') &&
				maxQty && (numRows >= maxQty)
			) {
				self.removeExtraRows();
			} else if (maxQty && (numRows > maxQty)) {
				if (maxQty === 1) {
					msg = self.sharedStorage.getLang('fieldOverLimit1');
				} else {
					msg = self.sharedStorage.getLang('fieldOverLimitQty');
				}

				self.overMaxMsg = F.controller.construct('Message', {
					autoRender: true,
					msg: msg.replace('{{qty}}', maxQty),
					sharedModel: self.sharedModel,
					sharedStorage: self.sharedStorage
				});
			}
		},

		/**
		 * Remove extra rows
		 */
		removeExtraRows: function() {
			// Save a reference to the controller
			var self = this;

			// Start a count var
			var count = 1;

			// Find all the rows
			self.$el.find('.js-ansel-row').each(function() {
				if (count > self.sharedModel.get('maxQty')) {
					$(this).remove();
				}

				count++;
			});
		}
	});
})(window.ANSEL);
