/**
 * This file is run after everything else
 */

(function(F) {
    'use strict';

    // Run stop number scroll controller on all number inputs
    $(':input[type=number]').each(function() {
        F.controller.construct('StopNumberScroll', {
            el: this
        });
    });

    // Run FieldsInit controller
    F.controller.construct('FieldsInit');
})(window.ANSEL);
