(function(F, DropZone) {
	'use strict';

	// Do not auto discover DropZones
	DropZone.autoDiscover = false;

	F.controller.make('DropZone', {
		/**
		 * @var sharedModel
		 */
		sharedModel: null,

		/**
		 * Shared storage
		 */
		sharedStorage: {
			dropZone: null
		},

		/**
		 * Initialize controller
		 */
		init: function() {
			// Save a reference to the constructor
			var self = this;

			// Get the dropzone container
			var $dropZoneContainer = self.$el.find('.js-ansel-dropzone');
			var dropZoneContainer = $dropZoneContainer.get(0);

			// Set should hide upload apparatus
			var shouldHideUploads = self.sharedModel.get('maxQty') &&
				self.sharedModel.get('preventUploadOverMax');

			// Save a variable for hide max items
			var $hideMaxEls;

			// Check if we should ever hide the upload apparatus
			if (shouldHideUploads) {
				$hideMaxEls = self.$el.find('.js-ansel-hide-max');

				// Watch for changes to numRows property
				self.sharedModelOther.onChange('numRows', function(val) {
					if (val >= self.sharedModel.get('maxQty')) {
						$hideMaxEls.hide();
					} else {
						$hideMaxEls.show();
					}
				});
			}

			// Create the DropZone
			self.sharedStorage.dropZone = new DropZone(dropZoneContainer, {
				url: $dropZoneContainer.data('uploadUrl'),
				params: {
					uploadKey: $dropZoneContainer.data('uploadKey'),
					minWidth: self.sharedModel.get('minWidth'),
					minHeight: self.sharedModel.get('minHeight')
				},
				dictDefaultMessage: self.sharedStorage.getLang('dragImagesToUpload'),
				dictFallbackMessage: self.sharedStorage.getLang('browserDoesNotSupportDragAndDrop'),
				dictFallbackText: self.sharedStorage.getLang('pleaseUseFallbackForm'),
				dictFileTooBig: self.sharedStorage.getLang('fileTooBig'),
				dictInvalidFileType: self.sharedStorage.getLang('invalidFileType'),
				dictCancelUpload: self.sharedStorage.getLang('cancelUpload'),
				dictCancelUploadConfirmation: self.sharedStorage.getLang('cancelUploadConfirmation'),
				dictRemoveFile: self.sharedStorage.getLang('removeFile'),
				dictMaxFilesExceeded: self.sharedStorage.getLang('youCannotUploadAnyMoreFiles')
			});

			// Look for the DropZone upload success
			self.sharedStorage.dropZone.on('success', function(file, json) {
				// Cast the preview element
				var $previewEl = $(file.previewElement);

				var ourJson = json;

				// What the hell, why don't all browsers treat this the same?
				if (typeof ourJson !== 'object') {
					ourJson = $.parseJSON(ourJson);
				}

				// Set a timeout and remove the preview element
				setTimeout(function() {
					$previewEl.fadeOut(200, function() {
						// Get the parent element
						var $parentEl = $previewEl.parent('.js-ansel-dropzone');

						// Look for other uploads in the area
						var $otherEls = $parentEl.find('.dz-image-preview')
							.not($previewEl);

						// Remove the preview element
						$previewEl.remove();

						// Remove appropriate classes from parent if applicable
						if (! $otherEls.length) {
							$parentEl.removeClass('dz-started');
						}
					});
				}, 2000);

				if (shouldHideUploads &&
					self.sharedModelOther.get('numRows') >= self.sharedModel.get('maxQty')
				) {
					return;
				}

				// Create a row
				F.controller.construct('Row', {
					sharedModel: self.sharedModel,
					sharedStorage: self.sharedStorage,
					uploadData: ourJson
				});

				$(document).trigger('entry:preview');
			});

			// Look for DropZone error
			self.sharedStorage.dropZone.on('error', function(file, json) {
				// Cast the preview element
				var $previewEl = $(file.previewElement);

				var ourJson = json;

				// What the hell, why don't all browsers treat this the same?
				if (typeof ourJson !== 'object') {
					ourJson = $.parseJSON(ourJson);
				}

				// If the min not met
				if (ourJson.error === 'Min not met') {
					// Show a message
					F.controller.construct('Message', {
						autoRender: true,
						msg: self.sharedStorage.getLang('minImageDimensionsNotMet'),
						sharedModel: self.sharedModel,
						sharedStorage: self.sharedStorage,
						destroyOnEvent: 'fieldChangeEvent'
					});

					// Set the error message on the actual element
					setTimeout(function() {
						$previewEl.find('.dz-error-message').find('span').text(
							self.sharedStorage.getLang('minImageDimensionsNotMet')
						);
					}, 100);
				}

				// Wait for a change event
				self.sharedModel.onChange('fieldChangeEvent', function() {
					$previewEl.fadeOut(200, function() {
						// Get the parent element
						var $parentEl = $previewEl.parent('.js-ansel-dropzone');

						// Look for other uploads in the area
						var $otherEls = $parentEl.find('.dz-image-preview')
							.not($previewEl);

						// Remove the preview element
						$previewEl.remove();

						// Remove appropriate classes from parent if applicable
						if (! $otherEls.length) {
							$parentEl.removeClass('dz-started');
						}
					});
				});
			});
		}
	});
})(window.ANSEL, window.Dropzone);
