(function(F) {
	'use strict';

	var template = '<div class="ansel-field__message ansel-field-message"></div>';

	F.controller.make('Message', {
		/**
		 * @var sharedModel
		 */
		sharedModel: null,

		/**
		 * Shared storage
		 */
		sharedStorage: {},

		/**
		 * Auto render
		 */
		autoRender: false,

		/**
		 * Destroy on event
		 */
		destroyOnEvent: null,

		/**
		 * Destroy after timeout
		 */
		destroyAfterTimeout: null,

		/**
		 * Text
		 */
		msg: '',

		/**
		 * Initialize controller
		 */
		init: function() {
			// Save a reference to the controller
			var self = this;

			// Set the element
			self.$el = $(template);
			self.el = self.$el.get(0);

			// Check auto render
			if (self.autoRender) {
				self.render();
			}
		},

		/**
		 * Render
		 */
		render: function() {
			// Save a reference to the controller
			var self = this;

			// Cast destroy after timeout to integer
			var destroyAfterTimeout = parseInt(self.destroyAfterTimeout);

			// Add text to element
			self.$el.html(self.msg);

			// Place the element
			self.sharedStorage.$messages.append(self.$el);

			// Destroy after timeout
			if (destroyAfterTimeout) {
				setTimeout(function() {
					self.destroy();
				}, destroyAfterTimeout);
			}

			// Destroy on event
			if (self.destroyOnEvent) {
				self.sharedModel.onChange(self.destroyOnEvent, function() {
					self.destroy();
				});
			}
		},

		/**
		 * Destroy
		 *
		 * @param {Boolean} animate
		 */
		destroy: function(animate) {
			// Save a reference to the controller
			var self = this;

			if (animate !== false) {
				self.$el.fadeOut(200, function() {
					self.$el.remove();
				});
			} else {
				self.$el.remove();
			}
		}
	});
})(window.ANSEL);
