(function(F, G, FLUID) {
	'use strict';

	F.controller.make('FieldsInit', {
		init: function() {
			// Save a reference to the controller
			var self = this;

			// Iterate over js fields and init
			$('.js-ansel-field').each(function() {
				self.initField($(this));
			});

			// Bloqs clone method means display method does not fire on clone
			G.bind('ansel', 'clone', function($cell) {
				$cell.find('.js-ansel-grid-field').each(function() {
					self.initField($(this), $cell, true);
				});
			});

			G.bind('ansel', 'display', function($cell) {
				$cell.find('.js-ansel-grid-field').each(function() {
					self.initField($(this), $cell);
				});
			});

			if (FLUID !== undefined) {
				FLUID.on('ansel', 'add', function($row) {
					$row.find('.js-ansel-field').each(function() {
						self.initField($(this), undefined, false, true);
					});
				});
			}
		},

		/**
		 * Init field
		 *
		 * @param {jQuery} $root - The root field element
		 * @param {jQuery|undefined} $gridOrBloqsCell
		 * @param {boolean} isClone
		 * @param {boolean} isFluid
		 */
		initField: function(
			$root,
			$gridOrBloqsCell,
			isClone,
			isFluid
		) {
			// Make sure it has not already been initialized
			if ($root.data('anselInit')) {
				return;
			}

			if (! isFluid && ! isClone) {
				$root.find('.js-ansel-field-template').each(function() {
					var $template = $(this);
					var $contents = $template.html();
					$template.after($contents);
				});

				// Remove temporary placeholder now that we've initiated the field.
				$root.find('.js-ansel-loading').remove();
			}

			// Construct a controller for this field
			F.controller.construct('Field', {
				el: $root,
				$gridOrBloqsCell: $gridOrBloqsCell,
				isClone: isClone
			});

			// Add the init data attribute
			$root.data('anselInit', true);
		}
	});
})(window.ANSEL, window.Grid, window.FluidField);
