(function(F) {
	'use strict';

	F.controller.make('EEFileChooser', {
		/**
		 * @var sharedModel
		 */
		sharedModel: null,

		/**
		 * Shared storage
		 */
		sharedStorage: {
			dropZone: null
		},

		/**
		 * Initialize controller
		 */
		init: function() {
			// Save a reference to the constructor
			var self = this;

			// We have to set a timeout because of EE
			setTimeout(function() {
				// Set up the EE file chooser callback
				self.$el.FilePicker({
					callback: function(file, references) {
						// Start an image variable
						var img = new Image();

						// Get min width
						var minWidth = self.sharedModel.get('minWidth');

						// Get min height
						var minHeight = self.sharedModel.get('minHeight');

						// Close the modal
						references.modal.find('.m-close').click();

						// Verify upload is an image
						if (! file.isImage) {
							// Show a message
							F.controller.construct('Message', {
								autoRender: true,
								msg: self.sharedStorage.getLang('fileIsNotAnImage'),
								sharedModel: self.sharedModel,
								sharedStorage: self.sharedStorage,
								destroyOnEvent: 'fieldChangeEvent'
							});

							return;
						}

						// Set up the on image load functionality
						img.onload = function() {
							// Check if image meets requirements
							if (
								(minWidth && img.width < minWidth) ||
								(minHeight && img.height < minHeight)
							) {
								// Show a message
								F.controller.construct('Message', {
									autoRender: true,
									msg: self.sharedStorage.getLang('minImageDimensionsNotMet'),
									sharedModel: self.sharedModel,
									sharedStorage: self.sharedStorage,
									destroyOnEvent: 'fieldChangeEvent'
								});

								// End processing here
								return;
							}

							// Create a row
							F.controller.construct('Row', {
								sharedModel: self.sharedModel,
								sharedStorage: self.sharedStorage,
								fileData: {
									// jscs:disable
									identifier: file.file_id, // jshint ignore:line
									// jscs:enable
									src: file.path
								}
							});
						};

						// Set the file path so the image will load
						img.src = file.path;
					}
				});
			}, 500);
		}
	});
})(window.ANSEL);
