(function(F) {
    'use strict';

    // Create a shared model constructor
    var SharedModelConstructor = F.model.make({
        fieldId: 'int',
        type: 'string',
        uploadDirectory: 'string',
        saveDirectory: 'string',
        minQty: 'int',
        maxQty: 'int',
        preventUploadOverMax: 'bool',
        quality: 'int',
        forceJpg: 'bool',
        retinaMode: 'bool',
        minWidth: 'int',
        minHeight: 'int',
        maxWidth: 'int',
        maxHeight: 'int',
        ratio: 'string',
        ratioWidth: 'float',
        ratioHeight: 'float',
        showTitle: 'bool',
        requireTitle: 'bool',
        titleLabel: 'string',
        showDescription: 'bool',
        requireDescription: 'bool',
        descriptionLabel: 'string',
        showCover: 'bool',
        requireCover: 'bool',
        coverLabel: 'string',
        fieldChangeEvent: 'int',
        coverRowId: 'int',
        prependToTable: 'bool',
        syncMetaFields: 'bool'
    });

    // Create shared other model constructor
    var SharedModelOtherConstructor = F.model.make({
        numRows: 'int'
    });

    F.controller.make('Field', {
        /**
         * @var sharedModel
         */
        sharedModel: null,

        /**
         * @var sharedModelOther
         */
        sharedModelOther: null,

        /**
         * Shared storage
         */
        sharedStorage: {
            lang: {},
            dropZone: null,
            rowTemplate: null,
            cropTableTemplate: null,
            $table: null,
            $tableBody: null,
            $messages: null,
            getLang: function(key) {
                var self = this;

                if (self.lang[key]) {
                    return self.lang[key];
                }

                return key;
            }
        },

        /**
         * Initialize controller
         */
        init: function() {
            // Save a reference to the controller
            var self = this;

            // Create a common object to send to controllers
            var commonObjSend;

            // Initialize field settings
            self.initFieldSettings();

            // Init lang
            self.initLang();

            // Get the row template
            // If this is Bloqs, we have to update the field names in the template ourselves because
            // Bloqs changed some things and field names in <script> tags don't get updated anymore
            if (self.$gridOrBloqsCell && self.$gridOrBloqsCell.hasClass('blocksft-atom')) {
                var $html = $(self.$el.find(
                    '.js-ansel-template__row'
                ).html());

                var blockId = self.$el.closest('.blocksft-block').data('id');

                $html.find('[name]').each(function() {
                    var $input = $(this);
                    var name = $input.attr('name');

                    $input.attr(
                        'name',
                        name.replace(
                            /blocks_new_block_\d+/gm,
                            blockId
                        )
                    );
                });

                self.sharedStorage.rowTemplate = $html.get(0).outerHTML;

                if (self.isClone) {
                    self.$el.find('.js-ansel-input-image-id').val('');
                    self.$el.find('.js-ansel-input-image-delete').val('');
                }
            } else {
                // Just get the row template, only Bloqs requires so much work

                self.sharedStorage.rowTemplate = self.$el.find(
                    '.js-ansel-template__row'
                ).html();
            }

            // Get the CropTable template
            self.sharedStorage.cropTableTemplate = self.$el.find(
                '.js-ansel-template__crop-table'
            ).html();

            // Set the messages container
            self.sharedStorage.$messages = self.$el.find('.js-ansel-messages');

            // Set the table
            self.sharedStorage.$table = self.$el.find('.js-ansel-table');
            self.sharedStorage.$tableBody = self.$el.find('.js-ansel-body');

            // Init sorting
            self.initSorting();

            // Set common object
            commonObjSend = {
                el: self.$el,
                sharedModel: self.sharedModel,
                sharedModelOther: self.sharedModelOther,
                sharedStorage: self.sharedStorage
            };

            // Initialize DropZone
            F.controller.construct('DropZone', commonObjSend);

            // Initialize rows
            F.controller.construct('Rows', commonObjSend);

            // Initialize existing rows
            self.$el.find('.js-ansel-row').each(function() {
                // Create a row
                F.controller.construct('Row', {
                    sharedModel: self.sharedModel,
                    sharedStorage: self.sharedStorage,
                    el: this
                });
            });

            // Initialize EE File Chooser
            self.$el.find('.js-ansel-ee-choose-existing-image').each(function() {
                F.controller.construct('EEFileChooser', {
                    el: this,
                    sharedModel: self.sharedModel,
                    sharedStorage: self.sharedStorage
                });
            });

            // Initialize Assets File Chooser
            self.$el.find('.js-ansel-assets-choose-existing-image').each(function() {
                F.controller.construct('AssetsFileChooser', {
                    el: this,
                    sharedModel: self.sharedModel,
                    sharedStorage: self.sharedStorage
                });
            });

            // Watch for change to numRows
            self.sharedModelOther.onChange('numRows', function() {
                self.$el.find('.js-ansel-field-input-placeholder').trigger(
                    'change'
                );
            });

            // Watch for generic field changes to trigger EE's validation
            self.$el.on('change', '.js-ansel-input', function() {
                self.$el.find('.js-ansel-field-input-placeholder').trigger(
                    'change'
                );
            });

            if (self.sharedStorage.$table.hasClass('js-ansel-sortable-grid')) {
                var $showMetaButton = self.$el.find('.js-ansel-show-meta');
                var $hideMetaButton = self.$el.find('.js-ansel-hide-meta');

                $showMetaButton.on('click', function(e) {
                    e.preventDefault();
                    self.sharedStorage.$tableBody.addClass('two-columns');
                    $showMetaButton.addClass('hidden');
                    $hideMetaButton.removeClass('hidden');
                });

                $hideMetaButton.on('click', function(e) {
                    e.preventDefault();
                    self.sharedStorage.$tableBody.removeClass('two-columns');
                    $hideMetaButton.addClass('hidden');
                    $showMetaButton.removeClass('hidden');
                });
            }

            if (! self.sharedModel.get('syncMetaFields')) {
                return;
            }

            // So the meta modal slide out works without needing another File field on the publish page.
            // See the css and js loading function in ft.ansel.php
            /* jshint ignore:start */
            EE.FileField.setup();
            /* jshint ignore:end */

            // Keep the file modal field values in sync with each image row
            self.$el.find('.js-ansel-edit-meta').each(function() {
                var $button = $(this);

                $button.on('click', function() {
                    var $initiator = $(this).closest('.js-ansel-row');

                    // Listen to all ajax requests being made. This is a little excessive
                    // but the only way to target the image slide out panel.
                    $(document).ajaxSuccess(function(event, xhr, settings) {
                        // It's an image modal view within the CP
                        var urlMatch = settings.url.match(/cp\/files\/file\/view\/(\d+)&modal_form=y/);

                        if (urlMatch) {
                            var titleSelector = '.file-preview-modal__form input[name=\'title\']';
                            var descSelector = '.file-preview-modal__form textarea[name=\'description\']';

                            $(document.body).off('keyup change', titleSelector);
                            $(document.body).on('keyup change', titleSelector, function(e) {
                                $initiator.find('.js-ansel-meta-title').val(e.target.value);
                            });

                            $(document.body).off('keyup change', descSelector);
                            $(document.body).on('keyup change', descSelector, function(e) {
                                $initiator.find('.js-ansel-meta-description').val(e.target.value);
                            });
                        }
                    });
                });
            });
        },

        /**
         * Initialize field settings
         */
        initFieldSettings: function() {
            // Save a reference to the controller
            var self = this;

            // Create an object for the settings
            var settingsObj = {};

            // Get raw field settings
            var rawSettings = self.$el.data('fieldSettings');

            // Iterate through the field settings and add to object
            for (var i in rawSettings) {
                if (rawSettings.hasOwnProperty(i)) {
                    settingsObj[i.toCamelCase()] = rawSettings[i];
                }
            }

            // Create a shared model with field settings
            self.sharedModel = new SharedModelConstructor(settingsObj);

            // Create the shared model other
            self.sharedModelOther = new SharedModelOtherConstructor();
        },

        /**
         * Init lang
         */
        initLang: function() {
            // Save a reference to the controller
            var self = this;

            // Create an object for the lang
            var langObj = {};

            // Get raw lang items
            var rawLang = self.$el.data('lang');

            // Iterate through the lang items and add to object
            for (var i in rawLang) {
                if (rawLang.hasOwnProperty(i)) {
                    langObj[i.toCamelCase()] = rawLang[i].replace(
                        '{{quotePlaceholder}}',
                        '\''
                    );
                }
            }

            // Add the lang to the shared object
            self.sharedStorage.lang = langObj;
        },

        /**
         * Init sorting
         */
        initSorting: function() {
            // Save a reference to the controller
            var self = this;

            var params = {
                // Fire 'beforeSort' event on sort start
                beforeSort: function(row) {
                    window.Grid.Settings.prototype._fireEvent('beforeSort', row);
                },
                // Fire 'afterSort' event on sort stop
                afterSort: function(row) {
                    // Jquery sortable sets the display property to table-cell, which breaks the grid styles, so remove it
                    row.removeAttr('style');

                    window.Grid.Settings.prototype._fireEvent('afterSort', row);
                    $(document).trigger('entry:preview');

                    // Trigger a generic field change event
                    self.sharedModel.set(
                        'fieldChangeEvent',
                        self.sharedModel.get('fieldChangeEvent') + 1
                    );
                },
                handle: '.js-grid-reorder-handle',
                cancel: '',
                containment: false,
                appendTo: 'parent'
            };

            if (self.sharedStorage.$table.hasClass('js-ansel-sortable-grid')) {
                params.sortableContainer = '.js-ansel-body';
                params.handle = '.js-grid-reorder-handle';
                params.item = '> .js-ansel-row';
                params.axis = false;
            }

            self.sharedStorage.$table.AnselTableReorder(params);
        }
    });
})(window.ANSEL);
