(function(F) {
    'use strict';

    F.controller.make('Row', {
        /**
         * @var sourceFileMissing
         */
        sourceFileMissing: false,

        /**
         * @var sharedModel
         */
        sharedModel: null,

        /**
         * Shared storage
         */
        sharedStorage: {},

        /**
         * Path/Url/ or base64 encoded
         *
         * @var {String} src
         */
        src: null,

        /**
         * Upload data
         */
        uploadData: {},

        /**
         * File data
         */
        fileData: {},

        /**
         * Reference image
         */
        referenceImg: null,

        /**
         * @var {Integer} imgWidth
         */
        imgWidth: 0,

        /**
         * @var {Integer} imgHeight
         */
        imgHeight: 0,

        /**
         * Local model
         */
        model: {
            orderNum: 'int',
            runCrop: 'int',
            coords: 'object'
        },

        /**
         * @var {HTMLInputElement} xInput
         */
        xInput: null,

        /**
         * @var {HTMLInputElement} yInput
         */
        yInput: null,

        /**
         * @var {HTMLInputElement} widthInput
         */
        widthInput: null,

        /**
         * @var {HTMLInputElement} heightInput
         */
        heightInput: null,

        /**
         * @var {HTMLInputElement} orderInput
         */
        orderInput: null,

        /**
         * @var {jQuery} $anselImageHolder
         */
        $anselImageHolder: null,

        /**
         * @var {jQuery} $anselImageHolderInner
         */
        $anselImageHolderInner: null,

        /**
         * @var {jQuery} $anselImage
         */
        $anselImage: null,

        /**
         * @var {Integer} rowId
         */
        rowId: null,

        /**
         * Events
         */
        events: {
            'click .js-ansel-input-cover': function() {
                // Save a reference to the controller
                var self = this;

                // Set the row ID to the shared model
                self.sharedModel.set('coverRowId', self.rowId);
            }
        },

        /**
         * Initialize controller
         */
        init: function() {
            // Save a reference to the controller
            var self = this;

            // Watch for changes to the field change event
            self.sharedModel.onChange('fieldChangeEvent', function() {
                self.checkOrder();
            });

            // Watch for changes to coords model property
            self.model.onChange('coords', function(val) {
                // Update coordinates inputs
                self.updateCoordsInputs(val);

                // Update thumbnail image position
                self.updateThumbImgPosition(val);
            });

            // Watch for changes to the cover row ID
            self.sharedModel.onChange('coverRowId', function(val) {
                // Check if val is not this rows ID
                if (val !== self.rowId) {
                    self.$el.find('.js-ansel-input-cover')
                        .addClass('off')
                        .removeClass('on')
                        .attr('data-state', 'off')
                    ;

                    self.$el.find('.js-ansel-input-cover input[type="hidden"]')
                        .val('n')
                    ;
                }
            });

            // Check if this is an upload or init on existing field
            if (Object.keys(self.fileData).length) {
                self.src = self.fileData.src;
                self.render();
            } else if (Object.keys(self.uploadData).length) {
                self.src = self.uploadData.base64;
                self.render();
            } else {
                self.setUp(true);
            }
        },

        /**
         * Render
         */
        render: function() {
            // Save a reference to the controller
            var self = this;

            // Create the element
            self.$el = $(self.sharedStorage.rowTemplate);
            self.el = self.$el.get(0);

            // Add the image
            self.$el.find('.js-ansel-row-image').attr(
                'src',
                self.src
            );

            // Set the file location path
            self.$el.find('.js-ansel-input-file-location').val(self.uploadData.anselCachePath);
            // Set the source file ID
            self.$el.find('.js-ansel-source-file-id').val(self.fileData.identifier);
            // Set the data ID used for the meta slide out
            self.$el.find('.js-file-input').data('id', self.fileData.identifier);

            // Add the row to the table body
            if (self.sharedModel.properties.prependToTable) {
                self.sharedStorage.$tableBody.prepend(self.$el);
            } else {
                self.sharedStorage.$tableBody.append(self.$el);
            }

            // Show the table
            self.sharedStorage.$table.parent('.table-responsive').jsShow();

            // Slight delay to make sure the DOM is settled
            setTimeout(function() {
                // Run setup
                self.setUp();
            }, 50);
        },

        /**
         * Set up
         *
         * @param {Boolean} setCoordsFromInput
         */
        setUp: function(setCoordsFromInput) {
            // Save a reference to the controller
            var self = this;

            // Get the image
            var $rowImg = self.$el.find('.js-ansel-row-image');

            // Check if the source file is missing
            if ($rowImg.data('sourceFileMissing')) {
                self.sourceFileMissing = true;
            }

            // Set jQuery variables
            self.$anselImage = $rowImg;
            self.$anselImageHolder = self.$el.find('.js-ansel-image-holder');
            self.$anselImageHolderInner = self.$el.find(
                '.js-ansel-image-holder-inner'
            );

            // Set up row ID
            self.setUpRowId();

            // Set up input variables
            self.setUpInputVariables();

            // Set up a reference image
            self.referenceImg = new Image();

            // Watch for load and set image dimensions
            self.referenceImg.onload = function() {
                self.imgWidth = self.referenceImg.width;
                self.imgHeight = self.referenceImg.height;

                if (setCoordsFromInput) {
                    self.setCoordsFromInput();
                }
            };

            // Set the reference image source
            self.referenceImg.src = $rowImg.attr('src');

            // Check if the source file is missing
            if (self.sourceFileMissing) {
                self.$el.find('.js-ansel-row-image').on('click', function() {
                    // Show a message
                    F.controller.construct('Message', {
                        autoRender: true,
                        msg: self.sharedStorage.getLang('sourceImageMissing'),
                        sharedModel: self.sharedModel,
                        sharedStorage: self.sharedStorage,
                        destroyOnEvent: 'fieldChangeEvent'
                    });
                });
            } else {
                // Create the AnselCrop controller for this row
                F.controller.construct('AnselCrop', {
                    $rowImage: self.$el.find('.js-ansel-row-image'),
                    model: self.model,
                    sharedStorage: self.sharedStorage,
                    sharedModel: self.sharedModel,
                    setInitialCoords: ! setCoordsFromInput
                });
            }

            // Watch for click on remove button
            self.$el.find('.js-ansel-remove-row').on('click', function(e) {
                e.preventDefault();
                self.destroy();
            });

            // Watch for click on image
            self.$el.find('.js-ansel-image-holder, .js-ansel-crop-row').on('click', function() {
                self.model.set('runCrop', self.model.get('runCrop') + 1);
            });

            // Trigger a generic field change event
            self.sharedModel.set(
                'fieldChangeEvent',
                self.sharedModel.get('fieldChangeEvent') + 1
            );
        },

        /**
         * Set up row ID
         */
        setUpRowId: function() {
            // Save a reference to the controller
            var self = this;

            // Find inputs
            var $rowInputs = self.$el.find('.js-ansel-input:not(.toggle-btn), .js-ansel-input.toggle-btn input[type="hidden"]');

            // Get the old row id
            var oldRowId = self.$el.data('rowId');

            // Create a new, unique row ID
            var rowId = Math.floor((Math.random() * 99999999999) + 1);

            // Set the row ID
            self.rowId = rowId;

            // Set the new row ID on the element (may use this some day)
            self.$el.data('rowId', rowId).attr('data-row-id', rowId);

            // Iterate over row inputs and update
            $rowInputs.each(function() {
                // Cast this element
                var $el = $(this);

                // Get the name attribute
                var name = $el.attr('name');

                // Replace the row ID portion
                name = name.replace(
                    'ansel_row_id_' + oldRowId,
                    'ansel_row_id_' + rowId
                );

                // Reset the name attribute
                $el.attr('name', name);
            });
        },

        /**
         * Set up input variables
         */
        setUpInputVariables: function() {
            // Save a reference to the controller
            var self = this;

            self.xInput = self.$el.find('.js-ansel-input-x').get(0);

            self.yInput = self.$el.find('.js-ansel-input-y').get(0);

            self.widthInput = self.$el.find('.js-ansel-input-width').get(0);

            self.heightInput = self.$el.find('.js-ansel-input-height').get(0);
        },

        /**
         * Check order
         */
        checkOrder: function() {
            // Save a reference to the controller
            var self = this;

            // Get the order
            var order = self.$el.prevAll('.js-ansel-row').length + 1;

            // Get max qty
            var maxQty = self.sharedModel.get('maxQty');

            // Set the order of this row
            self.model.set('orderNum', order);

            // Make sure order input has been set
            if (! self.orderInput) {
                self.orderInput = self.$el.find('.js-ansel-input-order').get(0);
            }

            // Set the value of the order input
            self.orderInput.value = order;

            // Check if we're over max allowed
            if (maxQty && order > maxQty) {
                self.$el.addClass('ansel-table__row--disabled');
            } else {
                self.$el.removeClass('ansel-table__row--disabled');
            }
        },

        /**
         * setCoordsFromInput
         */
        setCoordsFromInput: function() {
            // Save a reference to the controller
            var self = this;

            // Set the coordinates
            self.model.set('coords', {
                x: parseFloat(self.xInput.value),
                y: parseFloat(self.yInput.value),
                w: parseFloat(self.widthInput.value),
                h: parseFloat(self.heightInput.value)
            });
        },

        /**
         * Set coordinates
         *
         * @param {Object} coords
         */
        updateCoordsInputs: function(coords) {
            // Save a reference to the controller
            var self = this;

            self.xInput.value = Math.floor(coords.x);

            self.yInput.value = Math.floor(coords.y);

            self.widthInput.value = Math.min(
                Math.ceil(coords.w),
                self.imgWidth
            );

            self.heightInput.value = Math.min(
                Math.ceil(coords.h),
                self.imgHeight
            );
        },

        /**
         * Update Thumbnail Image Position
         *
         * @param {Object} coords
         */
        updateThumbImgPosition: function(coords) {
            // Save a reference to the controller
            var self = this;

            // Get the ratio
            var ratio = coords.w / coords.h;

            // Set holder dimensions
            var holderWidth = 168;
            var holderHeight = Math.round(holderWidth / ratio);

            // Set holder coordinates
            var rx = holderWidth / coords.w;
            var ry = holderHeight / coords.h;
            var thumbWidth = Math.round(rx * self.imgWidth);
            var thumbHeight = Math.round(ry * self.imgHeight);
            var thumbX = Math.round(rx * coords.x) * -1;
            var thumbY = Math.round(ry * coords.y) * -1;

            // Check if the source file is missing
            if (self.sourceFileMissing) {
                self.$anselImage.css('position', 'static');
                self.$anselImage.show();
                return;
            }

            // Set the thumbnail coords and position
            self.$anselImageHolderInner.css({
                height: holderHeight,
                width: holderWidth
            });
            self.$anselImage.css({
                height: thumbHeight + 'px',
                left: thumbX + 'px',
                top: thumbY + 'px',
                width: thumbWidth + 'px'
            });
            self.$anselImage.show();
        },

        /**
         * Destroy
         */
        destroy: function() {
            // Save a reference to the controller
            var self = this;

            // Check for siblings
            var siblingsLength = self.$el.siblings('tr').length;

            // Get the parent container
            var $formContainer = self.$el.closest('.js-ansel-field');

            // Get the delete input
            var $deleteInput = self.$el.find('.js-ansel-input-image-delete');

            // Get the ID input
            var $idInput = self.$el.find('.js-ansel-input-image-id');

            // Check if there is a parent container
            if (! $formContainer.length) {
                $formContainer = self.$el.closest('.js-ansel-grid-field');
            }

            // Check if this is an existing image
            if ($idInput.val()) {
                // Set delete input value
                $deleteInput.val('true');

                // Move the delete input out of the row
                $formContainer.prepend($deleteInput);

                // Move the ID input
                $formContainer.prepend($idInput);
            }

            // Remove the row
            self.$el.remove();

            // Hide the table if no more elements
            if (! siblingsLength) {
                self.sharedStorage.$table.parent('.table-responsive').jsHide();
            }

            // Trigger a generic field change event
            self.sharedModel.set(
                'fieldChangeEvent',
                self.sharedModel.get('fieldChangeEvent') + 1
            );
        }
    });
})(window.ANSEL);
