(function(F) {
	'use strict';

	F.controller.make('AssetsFileChooser', {
		/**
		 * @var sharedModel
		 */
		sharedModel: null,

		/**
		 * Shared storage
		 */
		sharedStorage: {
			dropZone: null
		},

		/**
		 * Initialize controller
		 */
		init: function() {
			// Save a reference to the controller
			var self = this;

			var sheet;

			// Make sure Assets is set up
			if (! window.Assets) {
				setTimeout(function() {
					self.init();
				}, 10);
				return;
			}

			// Prepare the assets sheet
			sheet = new window.Assets.Sheet({
				multiSelect: true,
				filedirs: [
					self.$el.data('fileDir')
				],
				kinds: [
					'image'
				],
				onSelect: function(files) {
					// Iterate through files
					files.forEach(function(i) {
						// Process the file selection
						self.processAssetsFileSelection(i);
					});
				}
			});

			// Watch for click on the button
			self.$el.on('click', function() {
				sheet.show();
			});
		},

		/**
		 * Process Assets File Selection
		 *
		 * @param {Object} file
		 */
		processAssetsFileSelection: function(file) {
			// Save a reference to the controller
			var self = this;

			// Start an image variable
			var img = new Image();

			// Get min width
			var minWidth = self.sharedModel.get('minWidth');

			// Get min height
			var minHeight = self.sharedModel.get('minHeight');

			// Set up the on image load functionality
			img.onload = function() {
				// Check if image meets requirements
				if (
					(minWidth && img.width < minWidth) ||
					(minHeight && img.height < minHeight)
				) {
					// Show a message
					F.controller.construct('Message', {
						autoRender: true,
						msg: self.sharedStorage.getLang('minImageDimensionsNotMet'),
						sharedModel: self.sharedModel,
						sharedStorage: self.sharedStorage,
						destroyOnEvent: 'fieldChangeEvent'
					});

					// End processing here
					return;
				}

				// Create a row
				F.controller.construct('Row', {
					sharedModel: self.sharedModel,
					sharedStorage: self.sharedStorage,
					fileData: {
						// jscs:disable
						identifier: file.id, // jshint ignore:line
						// jscs:enable
						src: file.url
					}
				});
			};

			// Set the file path so the image will load
			img.src = file.url;
		}
	});
})(window.ANSEL);
