(function(F) {
	'use strict';

	F.controller.make('GridSettingsSelect2', {
		/**
		 * On initialize
		 */
		init: function() {
			this.initSelect2Visible();
			this.initGridSelect2();
			this.initGridSelect2EE4();
		},

		/**
		 * Initialize select 2 on already visible fields
		 */
		initSelect2Visible: function() {
			// Iterate over each select
			$('.js-ansel-grid-select').each(function() {
				var $el = $(this);

				// If select2 has already been initialized, move on
				if ($el.data('select2-init') === true) {
					return;
				}

				// Wait a moment to make sure other things have run
				// (this sucks, but, you know, EE)
				setTimeout(function() {
					// Don't init on any disabled fields
					// EE has a duplicate for the field disabled and waiting
					if (! $el.prop('disabled')) {
						// Init select 2
						$el.select2({
							width: '100%'
						});

						// Set the data attribute
						$el.data('select2-init', true);
					}
				}, 500);
			});
		},

		/**
		 * Initialize select2 on grid field when field is selected
		 */
		initGridSelect2: function() {
			var self = this;
			var $gridColSel = $('.grid_col_select');

			// Remove any previously set change event for ansel grid column
			$gridColSel.off('change.anselColSelChange');

			// Set up the change event for the grid field type select
			$gridColSel.on('change.anselColSelChange', function() {
				var $sel = $(this);

				// If the select is set to ansel, initialize select2
				if ($sel.val() === 'ansel') {
					self.runGridSelect2($(this));
				}
			});

			// Set up the click function when adding a grid field
			$('.grid-tools').find('.add').on('click', function() {
				setTimeout(function() {
					self.initSelect2Visible();
					self.initGridSelect2();
				}, 500);
			});
		},

		initGridSelect2EE4: function() {
			$('body').on('change', '.fields-grid-common input', function() {
				var $sel = $(this);
				var $parent;
				var $sib;
				var $selects;

				if ($sel.val() !== 'ansel') {
					return;
				}

				$parent = $sel.closest('.fields-grid-common');
				$sib = $parent.next('.grid-col-settings-custom');
				$selects = $sib.find('.js-ansel-grid-select');

				$selects.each(function() {
					var $thisSel = $(this);

					if ($thisSel.data('select2-init')) {
						return;
					}

					$thisSel.select2({
						width: '100%'
					});

					$thisSel.data('select2-init', true);
				});
			});
		},

		/**
		 * Run grid select2
		 *
		 * @param {jQuery} $sel The grid column field type selector
		 */
		runGridSelect2: function($sel) {
			var self = this;
			// Get the column settings wrapper and find the select fields
			var $selects = $sel.parents('.grid-item')
				.find('.js-ansel-grid-select');

			// Wait until EE's JS has finished adding everything
			if (! $selects.length) {
				setTimeout(function() {
					self.runGridSelect2($sel);
				}, 100);

				return;
			}

			// Loop through the select fields
			$selects.each(function() {
				var $el = $(this);

				// Init select2
				$el.select2({
					width: '100%'
				});

				// Set the data attribute
				$el.data('select2-init', true);
			});
		}
	});
})(window.ANSEL);
