// Make sure Force JPG and Force WebP can't be selected at the same time

var $forceJpegToggleBtn = $('#fieldset-ansel_force_jpg .toggle-btn');
var $forceJpegToggleField = $('#fieldset-ansel_force_jpg input[name="ansel_force_jpg"]');

var $forceWebpToggleBtn = $('#fieldset-ansel_force_webp .toggle-btn');
var $forceWebpToggleField = $('#fieldset-ansel_force_webp input[name="ansel_force_webp"]');

$forceJpegToggleField.on('change', function() {
    if ($(this).val() === 'y') {
        $forceWebpToggleBtn.removeClass('on').addClass('off');
    }
});

$forceWebpToggleField.on('change', function() {
    if ($(this).val() === 'y') {
        $forceJpegToggleBtn.removeClass('on').addClass('off');
    }
});
